/// Model representing a schedule aggregation generated by the Schedule Aggregator Agent.
/// This is the structured output consumed by the Magazine Narrative UI.
class ScheduleAggregationModel {
  final String id;
  final DateTime generatedAt;
  final int version;
  final TimeRange timeRange;
  final HeroItem? heroItem;
  final String editorialIntro;
  final List<QuoteBlock> quoteBlocks;
  final List<TimelineDay> timeline;
  final List<CompletedItem> completed;
  final List<Conflict> conflicts;

  ScheduleAggregationModel({
    required this.id,
    required this.generatedAt,
    this.version = 1,
    required this.timeRange,
    this.heroItem,
    this.editorialIntro = '',
    this.quoteBlocks = const [],
    this.timeline = const [],
    this.completed = const [],
    this.conflicts = const [],
  });

  factory ScheduleAggregationModel.fromYaml(Map<String, dynamic> yaml) {
    return ScheduleAggregationModel(
      id: yaml['id'] as String? ?? '',
      generatedAt: _parseDateTime(yaml['generated_at']),
      version: yaml['version'] as int? ?? 1,
      timeRange: TimeRange.fromYaml(yaml['time_range'] as Map<String, dynamic>? ?? {}),
      heroItem: yaml['hero_item'] != null
          ? HeroItem.fromYaml(yaml['hero_item'] as Map<String, dynamic>)
          : null,
      editorialIntro: yaml['editorial_intro'] as String? ?? '',
      quoteBlocks: _parseList(yaml['quote_blocks'], QuoteBlock.fromYaml),
      timeline: _parseList(yaml['timeline'], TimelineDay.fromYaml),
      completed: _parseList(yaml['completed'], CompletedItem.fromYaml),
      conflicts: _parseList(yaml['conflicts'], Conflict.fromYaml),
    );
  }

  Map<String, dynamic> toJson() => {
    'id': id,
    'generated_at': generatedAt.toIso8601String(),
    'version': version,
    'time_range': timeRange.toJson(),
    if (heroItem != null) 'hero_item': heroItem!.toJson(),
    'editorial_intro': editorialIntro,
    'quote_blocks': quoteBlocks.map((e) => e.toJson()).toList(),
    'timeline': timeline.map((e) => e.toJson()).toList(),
    'completed': completed.map((e) => e.toJson()).toList(),
    'conflicts': conflicts.map((e) => e.toJson()).toList(),
  };

  static DateTime _parseDateTime(dynamic value) {
    if (value == null) return DateTime.now();
    if (value is DateTime) return value;
    if (value is String) return DateTime.tryParse(value) ?? DateTime.now();
    return DateTime.now();
  }

  static List<T> _parseList<T>(dynamic value, T Function(Map<String, dynamic>) parser) {
    if (value == null) return [];
    if (value is! List) return [];
    return value
        .whereType<Map>()
        .map((e) => parser(Map<String, dynamic>.from(e)))
        .toList();
  }
}

class TimeRange {
  final DateTime from;
  final DateTime to;

  TimeRange({required this.from, required this.to});

  factory TimeRange.fromYaml(Map<String, dynamic> yaml) {
    return TimeRange(
      from: _parseDate(yaml['from']),
      to: _parseDate(yaml['to']),
    );
  }

  Map<String, dynamic> toJson() => {
    'from': _formatDate(from),
    'to': _formatDate(to),
  };

  static DateTime _parseDate(dynamic value) {
    if (value == null) return DateTime.now();
    if (value is DateTime) return value;
    if (value is String) return DateTime.tryParse(value) ?? DateTime.now();
    return DateTime.now();
  }

  static String _formatDate(DateTime date) {
    return '${date.year}-${date.month.toString().padLeft(2, '0')}-${date.day.toString().padLeft(2, '0')}';
  }
}

class HeroItem {
  final String cardId;
  final String title;
  final String? description;
  final DateTime? startTime;
  final DateTime? endTime;
  final String? location;
  final int? priority;

  HeroItem({
    required this.cardId,
    required this.title,
    this.description,
    this.startTime,
    this.endTime,
    this.location,
    this.priority,
  });

  factory HeroItem.fromYaml(Map<String, dynamic> yaml) {
    return HeroItem(
      cardId: yaml['card_id'] as String? ?? yaml['id'] as String? ?? '',
      title: yaml['title'] as String? ?? '',
      description: yaml['description'] as String?,
      startTime: _parseDateTimeNullable(yaml['start_time']),
      endTime: _parseDateTimeNullable(yaml['end_time']),
      location: yaml['location'] as String?,
      priority: yaml['priority'] as int?,
    );
  }

  Map<String, dynamic> toJson() => {
    'card_id': cardId,
    'title': title,
    if (description != null) 'description': description,
    if (startTime != null) 'start_time': startTime!.toIso8601String(),
    if (endTime != null) 'end_time': endTime!.toIso8601String(),
    if (location != null) 'location': location,
    if (priority != null) 'priority': priority,
  };
}

class QuoteBlock {
  final String title;
  final String content;
  final String priority;
  final String? relatedCardId;

  QuoteBlock({
    required this.title,
    required this.content,
    this.priority = 'normal',
    this.relatedCardId,
  });

  factory QuoteBlock.fromYaml(Map<String, dynamic> yaml) {
    return QuoteBlock(
      title: yaml['title'] as String? ?? '',
      content: yaml['content'] as String? ?? '',
      priority: yaml['priority'] as String? ?? 'normal',
      relatedCardId: yaml['related_card_id'] as String?,
    );
  }

  Map<String, dynamic> toJson() => {
    'title': title,
    'content': content,
    'priority': priority,
    if (relatedCardId != null) 'related_card_id': relatedCardId,
  };
}

class TimelineDay {
  final String dayLabel;
  final DateTime? dayDate;
  final List<TimelineItem> items;

  TimelineDay({
    required this.dayLabel,
    this.dayDate,
    this.items = const [],
  });

  factory TimelineDay.fromYaml(Map<String, dynamic> yaml) {
    return TimelineDay(
      dayLabel: yaml['day_label'] as String? ?? '',
      dayDate: _parseDateTimeNullable(yaml['day_date']),
      items: _parseList(yaml['items'], TimelineItem.fromYaml),
    );
  }

  Map<String, dynamic> toJson() => {
    'day_label': dayLabel,
    if (dayDate != null) 'day_date': _formatDate(dayDate!),
    'items': items.map((e) => e.toJson()).toList(),
  };

  static String _formatDate(DateTime date) {
    return '${date.year}-${date.month.toString().padLeft(2, '0')}-${date.day.toString().padLeft(2, '0')}';
  }
}

class TimelineItem {
  final String cardId;
  final String title;
  final String status;
  final DateTime? startTime;
  final String type;
  final int? priority;
  final String? description;

  TimelineItem({
    required this.cardId,
    required this.title,
    this.status = 'pending',
    this.startTime,
    this.type = 'event',
    this.priority,
    this.description,
  });

  factory TimelineItem.fromYaml(Map<String, dynamic> yaml) {
    return TimelineItem(
      cardId: yaml['card_id'] as String? ?? yaml['id'] as String? ?? '',
      title: yaml['title'] as String? ?? '',
      status: yaml['status'] as String? ?? 'pending',
      startTime: _parseDateTimeNullable(yaml['start_time']),
      type: yaml['type'] as String? ?? 'event',
      priority: yaml['priority'] as int?,
      description: yaml['description'] as String?,
    );
  }

  Map<String, dynamic> toJson() => {
    'card_id': cardId,
    'title': title,
    'status': status,
    if (startTime != null) 'start_time': startTime!.toIso8601String(),
    'type': type,
    if (priority != null) 'priority': priority,
    if (description != null) 'description': description,
  };
}

class CompletedItem {
  final String cardId;
  final String title;
  final DateTime? completedAt;

  CompletedItem({
    required this.cardId,
    required this.title,
    this.completedAt,
  });

  factory CompletedItem.fromYaml(Map<String, dynamic> yaml) {
    return CompletedItem(
      cardId: yaml['card_id'] as String? ?? yaml['id'] as String? ?? '',
      title: yaml['title'] as String? ?? '',
      completedAt: _parseDateTimeNullable(yaml['completed_at']),
    );
  }

  Map<String, dynamic> toJson() => {
    'card_id': cardId,
    'title': title,
    if (completedAt != null) 'completed_at': completedAt!.toIso8601String(),
  };
}

class Conflict {
  final String description;
  final List<String> itemIds;

  Conflict({
    required this.description,
    this.itemIds = const [],
  });

  factory Conflict.fromYaml(Map<String, dynamic> yaml) {
    return Conflict(
      description: yaml['description'] as String? ?? '',
      itemIds: (yaml['item_ids'] as List?)?.cast<String>() ?? [],
    );
  }

  Map<String, dynamic> toJson() => {
    'description': description,
    'item_ids': itemIds,
  };
}

DateTime? _parseDateTimeNullable(dynamic value) {
  if (value == null) return null;
  if (value is DateTime) return value;
  if (value is String) return DateTime.tryParse(value);
  return null;
}

List<T> _parseList<T>(dynamic value, T Function(Map<String, dynamic>) parser) {
  if (value == null) return [];
  if (value is! List) return [];
  return value
      .whereType<Map>()
      .map((e) => parser(Map<String, dynamic>.from(e)))
      .toList();
}
